import * as React from 'react';
import Box from '@mui/material/Box';

// import SubHeader from '../SubHeader';

function Gallery ({ name }) {
	const cache = {};

	function importAll(r) {
		r.keys().forEach((key) => (cache[key] = r(key)));
	};

  // console.log('name', name);
  // console.log(`../../assets/collections/${name}`);

  // const gallery = name.trim().replace(/\s/g, '');

  // console.log('gallery', gallery);

  // const match = new RegExp(gallery + '-' + [0-9] + '.jpg')

	importAll(require.context('../assets/collections', false, /\.jpg/));
	const images = Object.entries(cache).map(module => module[1]);

  const gallery = () => {
    images.map((item) => {
      console.log('name', name);
      console.log('item', item);
      if (item.includes(name)) {
        console.log('MATCH')
      }
    })
  }

	return (
		<>
			{/* <SubHeader /> */}
      {gallery()}

			{/* move to gallery component  */}
			<Box
				display='flex'
				flexDirection='column'
				justifyContent='center'
				gap={2}
				sx={{
					margin: {
						// top | left and right | bottom
						// appbar 56px
						xs: '0px 30px 30px',
						sm: '0px 150px 30px',
						md: '0px 150px 30px',
						lg: '0px 400px 30px',
						xl: '0px 450px 30px',
					},
          backgroundColor: 'red'
					// backgroundColor: {
					// 	xs: 'red',
					// 	sm: 'yellow',
					// 	md: 'grey',
					// 	lg: 'blue',
					// 	xl: 'green'
					// }
				}}
			>
				{images.map((item) => {
					<Box component={'img'} src={item} flex={1}/>
        })}
			</Box>

		</>
	)
}

export default Gallery;
